
/**
 * 
 * @param arr 
 * @param left 
 * @param right 
 * @param k 
 * 
 * 快速选择，因为快排对于刻意编造的案例来说还是太慢了
 * 
 * 本质：对数组部分进行排序
 * 
 * 每次迭代，都不断根据基准值分区，然后确认最后要查找的数在哪个部分，然后对该部分进行排序
 * 
 * 这样查到最后就能查到了，当处于边界条件时，基准值就是所求top_k
 * 
 */
function QuickSelect(arr: number[], left: number, right: number, k: number): number {
    if(left >= right) return arr[left];

    /**
     * 1.随机选择基准值（避免最坏情况 O(n²)）
     */
    //随机选择一个基准数
    let randomIndex = left + Math.floor(Math.random() * (right - left + 1));
    //这里将基准值跟最左侧的值交换位置
    [arr[left], arr[randomIndex]] = [arr[randomIndex], arr[left]];
    let pivot = arr[left];

    /**
     * 2.三路分区（Dutch National Flag）：
     *    [left..lt-1]  < pivot
     *    [lt..gt]      == pivot
     *    [gt+1..right] > pivot
     * 
     * 例如[3,2,3,1,2,4,5,5,6]，选择pivot=3，那么第一次三路分区后：
     * 
     *  2   1   2   3   3   4   5   5   6
     *              |   |
     *             lt   gt
     * 
     * 显然，小于lt的都是小于pivot的，大于gt的都是大于pivot的
     * 并且第lt一直到第gt的元素都是3，这在有序数组中也一定成立
     *
     *    这样遇到大量重复元素时，== pivot 的区域直接跳过，
     *    范围严格缩小，避免 O(n²)
     */
    let lt = left;      // < pivot 区域的右边界 + 1
    let gt = right;     // > pivot 区域的左边界 - 1
    let i = left;       // 当前扫描位置（当前指针）

    //从左到右扫描
    while(i <= gt){ //为什么i必须小于等于gt？因为gt右边的数字一定大于pivot了，相当于自动完成了其中一路分区
        if(arr[i] < pivot){
            //当
            [arr[i], arr[lt]] = [arr[lt], arr[i]];
            lt++;
            i++;
        } else if(arr[i] > pivot){
            [arr[i], arr[gt]] = [arr[gt], arr[i]];
            gt--;
            // i 不自增，因为换过来的新元素还没检查（gt位置上不代表大于pivot）
        } else {
            i++;  // 等于 pivot，跳过
        }
    }

    /**
     * 3.剪枝：
     *    第 k 大元素 → 升序数组中的索引 = arr.length - k
     */
    let targetIdx = arr.length - k;
    if(targetIdx < lt){
        return QuickSelect(arr, left, lt - 1, k);    // 去 < pivot 区域
    } else if(targetIdx > gt){
        return QuickSelect(arr, gt + 1, right, k);   // 去 > pivot 区域
    } else {
        // lt <= targetIdx <= gt，就在 == pivot 区域中
        return arr[lt];  // 返回 pivot 即可
    }
}

function findKthLargest(nums: number[], k: number): number {
    //QuickSort(nums, 0, nums.length-1);
    //return nums[nums.length-k];
    return QuickSelect(nums, 0, nums.length-1, k);
}

